// Generates data/raidRoutes.ts — a tiny lookup from the raid/boss NAMES that
// data/itemSources.ts records to the raid + boss ROUTES this site publishes.
//
// Why a generated file instead of importing data/raids.ts directly: the item
// source line renders inside components/bis/GearGrid.tsx, a client component.
// Importing data/raids.ts there would ship all 48 boss strategies (~90 KB of
// prose) to the browser. This map is a few KB.
//
// Re-run after adding a raid or boss:  node scripts/build-raid-routes.mjs

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const SRC = fs.readFileSync(path.join(ROOT, "data/raids.ts"), "utf8");

// RAIDS entries are one-per-line object literals.
const raids = [...SRC.matchAll(/\{ id: "([^"]+)", name: "([^"]+)", phase: (\d+),/g)].map(
  (m) => ({ id: m[1], name: m[2], phase: Number(m[3]) }),
);

// BOSSES entries are multi-line; id/name/raidId/phase are the first fields.
const bosses = [
  ...SRC.matchAll(
    /^\s{4}id: "([^"]+)",\n\s{4}name: "([^"]+)",\n\s{4}raidId: "([^"]+)",\n\s{4}phase: (\d+),/gm,
  ),
].map((m) => ({ id: m[1], name: m[2], raidId: m[3], phase: Number(m[4]) }));

if (!raids.length || !bosses.length) {
  console.error("parse failed — raids:%d bosses:%d", raids.length, bosses.length);
  process.exit(1);
}

// Wowhead's sourcemore location strings don't always match our raid names.
const LOCATION_ALIASES = {
  "hyjal summit": "mount-hyjal",
  "the battle for mount hyjal": "mount-hyjal",
  "tempest keep": "tempest-keep",
  "the eye": "tempest-keep",
  "zul'aman": "zulaman",
};

const norm = (s) => s.toLowerCase().replace(/[^a-z0-9]/g, "");

const raidByKey = new Map();
for (const r of raids) raidByKey.set(norm(r.name), r);
for (const [alias, id] of Object.entries(LOCATION_ALIASES)) {
  const r = raids.find((x) => x.id === id);
  if (r) raidByKey.set(norm(alias), r);
  else console.warn("alias points at unknown raid id: %s", id);
}

const bossByKey = new Map();
for (const b of bosses) bossByKey.set(norm(b.name), b);

const lines = [];
lines.push("// GENERATED by scripts/build-raid-routes.mjs — do not edit by hand.");
lines.push("//");
lines.push("// Maps the raid/boss names recorded in data/itemSources.ts to the routes");
lines.push("// this site publishes, so a BiS item's \"how to get\" line can link to the");
lines.push("// actual boss guide. Kept free of data/raids.ts imports because it is");
lines.push("// reached from a client component.");
lines.push("");
lines.push("export interface RaidRoute {");
lines.push("  raidId: string;");
lines.push("  phase: number;");
lines.push("  /** Raid display name, for link text. */");
lines.push("  raid: string;");
lines.push("}");
lines.push("");
lines.push("export interface BossRoute extends RaidRoute {");
lines.push("  bossId: string;");
lines.push("  /** Boss display name, for link text. */");
lines.push("  boss: string;");
lines.push("}");
lines.push("");
lines.push("/** Normalised raid/location name → raid route. */");
lines.push("export const RAID_ROUTES: Record<string, RaidRoute> = {");
for (const [key, r] of [...raidByKey].sort())
  lines.push(`  ${JSON.stringify(key)}: { raidId: ${JSON.stringify(r.id)}, phase: ${r.phase}, raid: ${JSON.stringify(r.name)} },`);
lines.push("};");
lines.push("");
lines.push("/** Normalised boss name → boss route. */");
lines.push("export const BOSS_ROUTES: Record<string, BossRoute> = {");
for (const [key, b] of [...bossByKey].sort()) {
  const raid = raids.find((r) => r.id === b.raidId);
  lines.push(
    `  ${JSON.stringify(key)}: { raidId: ${JSON.stringify(b.raidId)}, phase: ${b.phase}, raid: ${JSON.stringify(raid?.name ?? b.raidId)}, bossId: ${JSON.stringify(b.id)}, boss: ${JSON.stringify(b.name)} },`,
  );
}
lines.push("};");
lines.push("");

fs.writeFileSync(path.join(ROOT, "data/raidRoutes.ts"), lines.join("\n"), "utf8");
console.log("data/raidRoutes.ts — %d raids, %d bosses", raidByKey.size, bossByKey.size);
